import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../../services/api';
import '../../styles/Clientes.css';

function CadastroCliente() {
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(false);
  const [formData, setFormData] = useState({
    nome: '',
    cpf_cnpj: '',
    celular: '',
    endereco: '',
    email: '',
    observacoes: ''
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      await api.criarCliente(formData);
      navigate('/clientes');
    } catch (error) {
      alert('Erro ao criar cliente: ' + error.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="sysmtec-container">
      <header className="sysmtec-header">
        <h1>SYSMTEC</h1>
        <h2>TELA DE CADASTRO DE CLIENTE</h2>
      </header>

      <div className="sysmtec-sidebar">
        <nav>
          <ul>
            <li><Link to="/agenda">Agenda</Link></li>
            <li className="active"><Link to="/clientes">Clientes</Link></li>
            <li><Link to="/projetos">Projetos e Serviços</Link></li>
            <li><Link to="/orcamentos">Orçamentos</Link></li>
            <li><Link to="/log">Log de alterações</Link></li>
          </ul>
        </nav>
      </div>

      <main className="sysmtec-main">
        <div className="panel">
          <h3>PANEL 🌟</h3>
          <Link to="/clientes" className="back-button">VOLTAR</Link>

          <form onSubmit={handleSubmit} className="cliente-form">
            <div className="form-group">
              <label>Insira o nome do cliente...</label>
              <input
                type="text"
                name="nome"
                value={formData.nome}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Insira o CPF/CNPJ do cliente...</label>
              <input
                type="text"
                name="cpf_cnpj"
                value={formData.cpf_cnpj}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Insira o celular do cliente...</label>
              <input
                type="text"
                name="celular"
                value={formData.celular}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Insira o endereço do cliente...</label>
              <input
                type="text"
                name="endereco"
                value={formData.endereco}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Insira o e-mail do cliente...</label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Observações sobre o cliente...</label>
              <textarea
                name="observacoes"
                value={formData.observacoes}
                onChange={handleChange}
              />
            </div>

            <button type="submit" disabled={isLoading} className="submit-button">
              {isLoading ? 'Salvando...' : 'Salvar Cliente'}
            </button>
          </form>
        </div>
      </main>
    </div>
  );
}

export default CadastroCliente;
